SELECT year, month, MIN(efficiency_score) AS min_efficiency_score
FROM energy_efficiency_metrics
GROUP BY year, month;

SELECT MIN(efficiency_score) 
FROM energy_efficiency_metrics 
WHERE year = 2023 AND month = 2;

SELECT meter_id, location, meter_accuracy
FROM energy_meters
WHERE meter_accuracy = (SELECT MAX(meter_accuracy) FROM energy_meters);

SELECT month, year, forecasted_kWh, forecast_date, created_at, updated_at 
FROM energy_forecasts 
WHERE month = 'June' AND year = 2023;

SELECT DISTINCT em.meter_id, em.location
FROM maintenance_logs as ml
JOIN energy_meters as em ON ml.meter_id = em.meter_id;

SELECT AVG(average_energy_consumption)
FROM (
    SELECT meter_id, AVG(energy_consumption_kWh) AS average_energy_consumption
    FROM energy_data
    GROUP BY meter_id
);

SELECT provider_id, contract_end
FROM energy_providers
ORDER BY contract_end DESC;

SELECT DISTINCT ed.meter_id, ed.P1_kW, ed.P2_kW, ed.P3_kW, ed.P4_kW
FROM energy_data AS ed
WHERE strftime('%Y-%m', ed.created_at) = '2020-10';
